function score(output, expected) {
  const items = output?.output?.items ?? [];
  if (items.length !== expected.itemCount) return 0;
  // Items should have confidence >= 'medium'
  for (const item of items) {
    if (item.confidence === 'speculation') return 0.5;
  }
  return 1.0;
}

function score(output, expected) {
  const items = output?.output?.items ?? [];
  return items.length === expected.itemCount ? 1.0 : 0.0;
}
